#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use DBI;
use Digest::bcrypt;
use CGI::Session;

# Configuration
my $db_name = 'your_database';
my $db_host = 'localhost';
my $db_user = 'db_username';
my $db_pass = 'db_password';

my $cgi = CGI->new();
print $cgi->header('text/html');

my $username = $cgi->param('username') // '';
my $password = $cgi->param('password') // '';

if ($cgi->request_method() eq 'POST' && $username ne '' && $password ne '') {

    my $dsn = "DBI:mysql:database=$db_name;host=$db_host";
    my $dbh = DBI->connect($dsn, $db_user, $db_pass, {
        RaiseError  => 1,
        PrintError  => 0,
        AutoCommit  => 1,
        mysql_enable_utf8mb4 => 1,
    });

    # SECURE: Using placeholders (?) instead of string interpolation.
    # DBI sends the query and parameters separately to the database,
    # making SQL injection impossible.
    my $sth = $dbh->prepare(
        "SELECT id, username, password_hash FROM users WHERE username = ?"
    );
    $sth->execute($username);

    my $row = $sth->fetchrow_hashref();
    $sth->finish();
    $dbh->disconnect();

    if ($row) {
        # Compare the provided password against the stored bcrypt hash.
        # Passwords should NEVER be stored in plain text.
        my $stored_hash = $row->{password_hash};

        if (_verify_password($password, $stored_hash)) {
            # Create a session for the authenticated user
            my $session = CGI::Session->new("driver:File", undef, {Directory => '/tmp'});
            $session->param('user_id', $row->{id});
            $session->param('username', $row->{username});
            $session->param('logged_in', 1);
            $session->expire('+1h');

            print $cgi->start_html(-title => 'Login Successful');
            print "<h1>Welcome, " . CGI::escapeHTML($row->{username}) . "!</h1>";
            print "<p>You have been successfully authenticated.</p>";
            print "<p>Session ID: " . $session->id() . "</p>";
