# --- Helper Subroutines ---

sub _verify_password {
    my ($plain_password, $stored_hash) = @_;

    # Using Crypt::Eksblowfish::Bcrypt for bcrypt comparison
    # Install via: cpan Crypt::Eksblowfish::Bcrypt
    require Crypt::Eksblowfish::Bcrypt;

    my $check_hash = Crypt::Eksblowfish::Bcrypt::bcrypt($plain_password, $stored_hash);
    return ($check_hash eq $stored_hash) ? 1 : 0;
}

